import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink", () => {
  it("should pass the specific abort error to read when abort is set and op returns false", (done) => {
    const specificAbortError = new Error("specific abort error");
    const readEndValues: any[] = [];
    let dataProvided = false;
    let sinkInstance: any;

    const source = (end: any, cb: Function) => {
      if (!dataProvided && end === null) {
        dataProvided = true;
        cb(null, "somedata");
      } else {
        readEndValues.push(end);
        cb(end || true, null);
      }
    };

    sinkInstance = drain((data: any) => {
      // Abort with specific error, then return false to trigger the else-if branch
      sinkInstance.abort(specificAbortError);
      return false;
    }, (err: any) => {
      // Find the read call that came from the else-if branch (not from sink.abort directly)
      // Original: read(abort || true) = read(specificAbortError)
      // Mutated: read(true)
      const hasSpecificError = readEndValues.some(v => v === specificAbortError);
      try {
        expect(hasSpecificError).toBe(true);
        done();
      } catch(e) {
        done(e);
      }
    });

    sinkInstance(source);
  });
});
